from dataclasses import dataclass
from typing import List

@dataclass
class CacheConfig:
    atomicity_mode: str
    cache_mode: str
    write_synchronization_mode: str

def initialize_cache_config() -> CacheConfig:
    atomicity_mode = "ATOMIC"
    cache_mode = "PARTITIONED"
    write_synchronization_mode = "FULL_SYNC"
    return CacheConfig(atomicity_mode, cache_mode, write_synchronization_mode)

def validate_cache_config(config: CacheConfig) -> bool:
    valid_atomicity_modes = ["ATOMIC", "TRANSACTIONAL"]
    valid_cache_modes = ["PARTITIONED", "REPLICATED"]
    valid_write_sync_modes = ["FULL_SYNC", "PRIMARY_SYNC", "FULL_ASYNC"]

    if config.atomicity_mode not in valid_atomicity_modes:
        return False
    if config.cache_mode not in valid_cache_modes:
        return False
    if config.write_synchronization_mode not in valid_write_sync_modes:
        return False
    return True

def display_cache_config(config: CacheConfig) -> None:
    print(f"Atomicity Mode: {config.atomicity_mode}")
    print(f"Cache Mode: {config.cache_mode}")
    print(f"Write Synchronization Mode: {config.write_synchronization_mode}")

def main() -> None:
    config = initialize_cache_config()
    if validate_cache_config(config):
        display_cache_config(config)
    else:
        print("Invalid cache configuration.")

if __name__ == "__main__":
    main()
